332	    info!("");
333	    info!("Done! Project created at {}", project_dir.display());
334	    info!("  Code repo:    {code_repo}  (chid={code_chid_final})");
335	    info!("  Session repo: {session_repo}  (chid={session_chid_final})");
336	    info!(
337	        "  Symlink:      {} -> {}",
338	        sl.symlink_path.display(),
339	        sl.abs_target.display()
340	    );
341	
342	    debug!("init: exit");
343	    Ok(())
344	}
