327	/// Collect commit IDs for `..x..` (both directions) or any dot notation.
328	///
329	/// Returns `(commit_ids, anchor_index)` — the IDs in display order
330	/// (descendants closest to anchor, anchor, ancestors closest to anchor)
331	/// and the index of the anchor commit within the list.
332	///
333	/// - `desc_count`: `Some(n)` = n closest descendants, `None` = all, `Some(0)` = none
334	/// - `anc_count`: `Some(n)` = n closest ancestors, `None` = all, `Some(0)` = none
335	pub fn collect_ids(
336	    workspace: &Workspace,
337	    repo: &Arc<ReadonlyRepo>,
338	    rev: &str,
339	    desc_count: Option<usize>,
340	    anc_count: Option<usize>,
341	) -> Result<(Vec<CommitId>, usize), Box<dyn std::error::Error>> {
342	    let anchor_ids = resolve_revset(workspace, repo, rev)?;
343	    if anchor_ids.is_empty() {
344	        return Err(format!("no commit found for revision '{rev}'").into());
345	    }
346	    let anchor_id = &anchor_ids[0];
347	    let root_commit_id = repo.store().root_commit_id().clone();
348	
349	    // Descendants (closest to anchor)
350	    let mut desc_ids: Vec<CommitId> = Vec::new();
351	    if desc_count != Some(0) {
352	        let descendant_ids = resolve_revset(workspace, repo, &format!("{rev}::"))?;
353	        desc_ids = descendant_ids
354	            .into_iter()
355	            .filter(|id| *id != root_commit_id && *id != *anchor_id)
356	            .collect();
357	        if let Some(n) = desc_count {
358	            let start = desc_ids.len().saturating_sub(n);
359	            desc_ids = desc_ids[start..].to_vec();
360	        }
361	    }
362	
363	    // Ancestors (closest to anchor)
364	    let mut anc_ids: Vec<CommitId> = Vec::new();
365	    if anc_count != Some(0) {
366	        let ancestor_ids = resolve_revset(workspace, repo, &format!("::{rev}"))?;
367	        let limit = anc_count.unwrap_or(usize::MAX); // OK: no --ancestors limit → unbounded
368	        let mut count = 0;
369	        for commit_id in ancestor_ids {
370	            if commit_id == root_commit_id || commit_id == *anchor_id {
371	                continue;
372	            }
373	            anc_ids.push(commit_id);
374	            count += 1;
375	            if count >= limit {
376	                break;
377	            }
378	        }
379	    }
380	
381	    let anchor_index = desc_ids.len();
382	    let mut result = desc_ids;
383	    result.push(anchor_id.clone());
384	    result.extend(anc_ids);
385	    Ok((result, anchor_index))
386	}
