50	/// Run a command with retries, sleeping between attempts.
51	fn run_retry(
52	    cmd: &str,
53	    args: &[&str],
54	    cwd: &Path,
55	    retries: u32,
56	    delay_secs: u64,
57	) -> Result<String, Box<dyn std::error::Error>> {
58	    let mut last_err = String::new();
59	    for attempt in 1..=retries {
60	        match run(cmd, args, cwd) {
61	            Ok(out) => {
62	                if attempt > 1 {
63	                    debug!("succeeded after {attempt} attempts");
64	                }
65	                return Ok(out);
66	            }
67	            Err(e) => {
68	                last_err = e.to_string();
69	                if attempt < retries {
70	                    debug!("attempt {attempt}/{retries} failed: {last_err}");
71	                    debug!("retrying in {delay_secs}s...");
72	                    std::thread::sleep(std::time::Duration::from_secs(delay_secs));
73	                }
74	            }
75	        }
76	    }
77	    Err(format!("failed after {retries} attempts: {last_err}").into())
